head.script:
/**
 * 화 면 명 : 상여예산전표투입
 * 메뉴경로 : 회계/관리회계/실적관리/실적집계/예산전표관리/
 * ASIS경로 : /debis/dongwon-debis-engine/src/main/webapp/ac/co/rsltsmgnt/rsltsaggr/co_403_04_02b.jsp
 * 작 성 자 : 배기원
 * 작 업 일 : 2025-12-05
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅(UDC), 그리드(데이터리스트)
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 * 참고사항
 *    1. login정보 확인 필요 
 *     ☞  $c.data.getMemInfo() 처리
 *    2. [해결]<%@ page import="dbl.ac.am.constants.ACConstants" %> 상수가져오는건 공통에서 글로벌 상수로 변경할 듯. 
 *    3. 상수값 가져오는거 어떻게 할지? DGlobalValue.java 이런거 있을때마다 개발자가 DGlobalValue.js로 변경해서 올려야 하나?
 *    4. 엑셀 업로드 기능(gridUpYn="Y", 그리드_onfilereadend)
 *    5. 계정코드 : 4200220, 원)제수당-상여 만 나오도록 되어 있음
 * 수정이력 :
 *    - 2025-12-05      배기원    최초작성
 */
//hidden값
scwin.txtBeBudgetYm = "";
scwin.check = "";

//로그인 정보
scwin.memJson;
scwin.vLoginCoCd;
scwin.vLoginCoClsCd;
scwin.vUserHomeClsCd;
scwin.vCoCd;
scwin.isSubCompany;

scwin.f_commCdPopupRow = 0;     //그리드 팝업 호출 시 ROW값
scwin.oldValue = "";            //그리드 팝업 호출 시 비교값

/**
 * TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
 */
scwin.onpageload = function() {
    scwin.memJson = $c.data.getMemInfo();
    scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.memJson["coCd"]) ? "" : scwin.memJson["coCd"];                      //소속자회사
    scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.memJson["coClsCd"]) ? "" : scwin.memJson["coClsCd"];             //회계_회사구분('CO035' : 0:동부 EXPRESS)
    scwin.vUserHomeClsCd = $c.gus.cfIsNull(scwin.memJson["userHomeClsCd"]) ? "" : scwin.memJson["userHomeClsCd"];//사용자소속구분코드
    scwin.vCoCd = $c.gus.cfIsNull(scwin.memJson["coCd"]) ? "" : scwin.memJson["coCd"];                           //회사코드
    scwin.isSubCompany = false;
};


/**
 * 초기세팅(TOBE 그리드, 총건수)
 */
scwin.setInit = function() {
    gr_budget.setNoResultMessageVisible(false);
    ds_budget.reform();
    ds_budget.removeAll();
    totalRows.setValue("0");
    scwin.f_commCdPopupRow = 0;     //그리드 팝업 호출 시 ROW값
};

/**
 * UDC값 초기화(scwin.onpageload 이후 세팅됨)
 */
scwin.onUdcCompleted = function() {
    scwin.setInit();
    scwin.f_Setting();
    $c.gus.cfDisableBtn([btn_rowAdd, btn_rowDel, btn_cancel, btn_save]);
    scwin.f_setCompanyInfo();
};

/**
 * 조회초기 필드 Clear
 */
scwin.f_FieldClear = function (e) {
    // $c.gus.cfInitObjects(tbl_search, [ica_budgetYm, ed_acctCd, ed_acctNm, ed_acctDeptCd, ed_acctDeptNm, ed_coCd, ed_coNm]);
    $c.gus.cfInitObjects(tbl_search, [ica_budgetYm, ed_coCd, ed_coNm]);
    scwin.f_Setting();
};


/**
* 조회버튼
*/
scwin.f_Retrieve = async function() {
    let ret = await $c.gus.cfValidate([ica_budgetYm, ed_acctDeptCd, ed_acctCd]);
    if (!ret) {
        return false;
    }
    if(ica_budgetYm.getValue().length != 6){
        await $c.gus.cfAlertMsg("예산년월은(는) 6자리수만큼 입력하십시오.");
        ica_budgetYm.focus();
        return;
    }
    ret = await $c.date.isDate(ica_budgetYm.getValue()+"01");
    if(!ret) {
        await $c.gus.cfAlertMsg("올바른 예산년월을(를) 입력하십시오.");
        ica_budgetYm.focus();
        return;
    }
    scwin.txtBeBudgetYm = "";
    scwin.check = "";
    dma_search.set("beBudgetYm", scwin.txtBeBudgetYm);
    scwin.setInit();
    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    // $c.gus.cfEnableObjects([btn_rowAdd, btn_rowDel, btn_cancel, btn_save]);
    $c.gus.cfEnableBtnOnly([btn_rowAdd, btn_rowDel, btn_cancel, btn_save]);
    gr_budget.setNoResultMessageVisible(true);
    let rowCnt = ds_budget.getRowCount();
    totalRows.setValue(rowCnt);
    if (rowCnt > 0) {
        ds_budget.reform();
        gr_budget.setFocusedCell(0, 0);
    } else {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다
    }
};

scwin.sbm_retrieve_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg)
};


/**
 * 전월자료복사
 */
scwin.f_LastCopy = async function () {
    let ret = await $c.gus.cfValidate([ica_budgetYm]);
    if (!ret) {
        return false;
    }
    ret = await $c.date.isDate(ica_budgetYm.getValue()+"01");
    if(!ret) {
        await $c.gus.cfAlertMsg("마감년월은(는) 6자리수만큼 입력하십시오.");
        ica_budgetYm.focus();
        return;
    }

    if (await $c.win.confirm("전월자료를 복사하시면 기존데이타는 삭제됩니다. <BR>복사하시겠습니까?")) {        
        scwin.txtBeBudgetYm = await $c.date.addMonth(ica_budgetYm.getValue()+"01", "-1");
        scwin.check = "Y";
        dma_search.set("beBudgetYm", scwin.txtBeBudgetYm.substring(0, 6));
        $c.sbm.execute(sbm_retrieve);
    }
};


